import { useState, useRef, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import { UploadCloud, CheckCircle, AlertTriangle, FileText, ChevronRight, Briefcase, Zap } from "lucide-react";

const BASE_URL = "http://127.0.0.1:8000/api";

function Apply() {
  const [searchParams] = useSearchParams();
  const initialVacancyId = searchParams.get("jobId") || 1;
  const jobTitle = searchParams.get("jobTitle") || "Backend Python Developer";

  const [form, setForm] = useState({ name: "", email: "", vacancy_id: initialVacancyId });
  const [resume, setResume] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [dragActive, setDragActive] = useState(false);

  const fileInputRef = useRef(null);

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setResume(e.dataTransfer.files[0]);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!resume || !form.name || !form.email) return;

    setLoading(true);
    setResult(null);

    const data = new FormData();
    data.append("name", form.name);
    data.append("email", form.email);
    data.append("vacancy_id", form.vacancy_id);
    data.append("resume_file", resume);

    try {
      const res = await axios.post(`${BASE_URL}/evaluate/`, data);
      setResult(res.data);
    } catch (err) {
      console.error(err);
      alert("Error submitting application");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex justify-center items-center py-10">
      <div className="w-full max-w-4xl grid md:grid-cols-2 gap-8 items-start">

        {/* Left Side: Copy & Info */}
        <motion.div
          initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5 }}
          className="flex flex-col space-y-6"
        >
          <div className="inline-flex items-center space-x-2 bg-indigo-500/10 text-indigo-400 px-3 py-1 rounded-full w-max text-sm font-medium">
            <Zap className="w-4 h-4" />
            <span>AI-Powered Recruitment</span>
          </div>

          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight text-white leading-tight">
            Apply for <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-cyan-400">{jobTitle}</span>
          </h1>

          <p className="text-slate-400 text-lg">
            Join our cutting-edge engineering team. Our AI natively evaluates your resume securely and provides instant feedback on your application.
          </p>

          <div className="bg-slate-800/50 backdrop-blur border border-slate-700/50 rounded-2xl p-6 mt-6">
            <h3 className="text-lg font-semibold text-white mb-4 flex items-center">
              <Briefcase className="w-5 h-5 mr-2 text-indigo-400" />
              What we're looking for
            </h3>
            <ul className="space-y-3 text-sm text-slate-300">
              <li className="flex items-start">
                <CheckCircle className="w-5 h-5 mr-3 text-emerald-400 shrink-0" />
                <span>Strong experience with Python & Django</span>
              </li>
              <li className="flex items-start">
                <CheckCircle className="w-5 h-5 mr-3 text-emerald-400 shrink-0" />
                <span>API Design & Database Management</span>
              </li>
              <li className="flex items-start">
                <CheckCircle className="w-5 h-5 mr-3 text-emerald-400 shrink-0" />
                <span>Active GitHub profile with relevant projects</span>
              </li>
            </ul>
          </div>
        </motion.div>

        {/* Right Side: Form */}
        <motion.div
          initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5, delay: 0.2 }}
          className="bg-slate-800/60 backdrop-blur-xl border border-slate-700 shadow-2xl rounded-3xl p-8 relative overflow-hidden"
        >
          {/* Subtle glow effect behind form */}
          <div className="absolute top-0 right-0 -mr-20 -mt-20 w-64 h-64 bg-indigo-500/20 rounded-full blur-3xl pointer-events-none" />

          <h2 className="text-2xl font-bold text-white mb-6 relative z-10">Application details</h2>

          <form onSubmit={handleSubmit} className="space-y-6 relative z-10">
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Full Name</label>
                <input
                  type="text"
                  required
                  className="w-full bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-500"
                  placeholder="John Doe"
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Email Address</label>
                <input
                  type="email"
                  required
                  className="w-full bg-slate-900/50 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all placeholder-slate-500"
                  placeholder="john@example.com"
                  onChange={(e) => setForm({ ...form, email: e.target.value })}
                />
              </div>

              {/* Custom File Upload */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Resume (PDF)</label>
                <div
                  className={`mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-dashed rounded-xl transition-all cursor-pointer ${dragActive ? 'border-indigo-500 bg-indigo-500/10' : 'border-slate-600 hover:border-slate-500 bg-slate-900/30 hover:bg-slate-900/50'
                    }`}
                  onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop}
                  onClick={() => fileInputRef.current.click()}
                >
                  <div className="space-y-1 text-center flex flex-col items-center">
                    {resume ? (
                      <div className="flex flex-col items-center space-y-2">
                        <FileText className="w-10 h-10 text-indigo-400 mb-2" />
                        <span className="text-sm text-white font-medium break-words px-2 text-center w-full max-w-[200px] truncate">{resume.name}</span>
                        <span className="text-xs text-slate-400 hover:text-indigo-400" onClick={(e) => { e.stopPropagation(); setResume(null); }}>Change file</span>
                      </div>
                    ) : (
                      <>
                        <UploadCloud className="w-10 h-10 text-slate-400 mb-2" />
                        <div className="flex text-sm text-slate-300">
                          <span className="relative font-medium text-indigo-400 hover:text-indigo-300">Upload a file</span>
                          <p className="pl-1">or drag and drop</p>
                        </div>
                        <p className="text-xs text-slate-500">PDF up to 10MB</p>
                      </>
                    )}
                  </div>
                </div>
                <input
                  type="file"
                  accept="application/pdf"
                  ref={fileInputRef}
                  className="hidden"
                  onChange={(e) => setResume(e.target.files[0])}
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading || !resume || !form.name || !form.email}
              className="w-full relative group overflow-hidden bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-700 disabled:cursor-not-allowed text-white font-bold py-3 px-4 rounded-xl transition-all shadow-lg shadow-indigo-600/20 active:scale-[0.98]"
            >
              {loading ? (
                <span className="flex items-center justify-center">
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Processing with AI...
                </span>
              ) : (
                <span className="flex items-center justify-center">
                  Submit Application <ChevronRight className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                </span>
              )}
            </button>
          </form>

          {/* Result Slide-in */}
          <AnimatePresence>
            {result && (
              <motion.div
                initial={{ opacity: 0, height: 0, y: 10 }}
                animate={{ opacity: 1, height: 'auto', y: 0 }}
                exit={{ opacity: 0, height: 0 }}
                className="mt-6 pt-6 border-t border-slate-700"
              >
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-lg font-bold text-white">Analysis Complete</h3>
                  <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${result.status === 'hired' ? 'bg-emerald-500/20 text-emerald-400' :
                    result.status === 'ai_rejected' ? 'bg-red-500/20 text-red-400' : 'bg-amber-500/20 text-amber-400'
                    }`}>
                    {result.status.replace('_', ' ')}
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 mb-4">
                  <div className="bg-slate-900/50 border border-slate-700 rounded-xl p-4 flex flex-col items-center justify-center text-center shadow-inner">
                    <span className="text-slate-400 text-xs uppercase tracking-wider font-semibold mb-1">AI Score</span>
                    <span className="text-3xl font-black text-white">{result.ai_score}<span className="text-sm text-slate-500 font-medium">/100</span></span>
                  </div>

                  <div className="bg-slate-900/50 border border-slate-700 rounded-xl p-4 flex flex-col items-center justify-center text-center shadow-inner">
                    <span className="text-slate-400 text-xs uppercase tracking-wider font-semibold mb-1">Verification</span>
                    <span className={`text-lg font-bold capitalize pt-1 ${result.verification_status === 'verified' ? 'text-emerald-400' :
                      result.verification_status === 'suspicious' ? 'text-amber-400' : 'text-red-400'
                      }`}>
                      {result.verification_status}
                    </span>
                  </div>
                </div>

                {result.verification_reason && (
                  <div className="bg-indigo-500/5 border border-indigo-500/10 rounded-xl p-4">
                    <p className="text-sm text-slate-300 leading-relaxed italic border-l-2 border-indigo-500 pl-3">
                      "{result.verification_reason}"
                    </p>
                  </div>
                )}
              </motion.div>
            )}
          </AnimatePresence>

        </motion.div>
      </div>
    </div>
  );
}

export default Apply;

import { useEffect, useState } from "react";
import axios from "axios";
import { motion } from "framer-motion";
import { Link } from "react-router-dom";
import { Briefcase, ArrowRight, Zap, Code, ShieldCheck, Database, Layout } from "lucide-react";

const BASE_URL = "http://127.0.0.1:8000/api";

function CandidateDashboard() {
  const [vacancies, setVacancies] = useState([]);
  const [loading, setLoading] = useState(true);

  // Dynamic icon mapper function based on title keywords
  const getJobIcon = (title) => {
    const t = title.toLowerCase();
    if (t.includes('frontend') || t.includes('ui') || t.includes('design')) return <Layout className="w-6 h-6 text-emerald-400" />;
    if (t.includes('data') || t.includes('machine') || t.includes('ai')) return <Database className="w-6 h-6 text-amber-400" />;
    return <Code className="w-6 h-6 text-indigo-400" />; // default for backend/engineering
  };

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get(`${BASE_URL}/vacancies/`);
        // Only show open vacancies on candidate side, though right now all are considered 'open'
        setVacancies(res.data);
      } catch (err) {
        console.error("Failed to fetch jobs:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="flex flex-col items-center">
          <svg className="animate-spin h-10 w-10 text-indigo-500 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="text-slate-400 font-medium tracking-wide animate-pulse">Loading Open Roles...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-10 pb-12">
      {/* Hero Section */}
      <div className="relative overflow-hidden bg-slate-800/40 border border-slate-700/50 backdrop-blur-xl p-8 md:p-12 rounded-3xl shadow-xl flex flex-col items-center text-center">
        <div className="absolute top-0 right-0 -mr-20 -mt-20 w-64 h-64 bg-indigo-500/10 rounded-full blur-3xl pointer-events-none" />
        <div className="absolute bottom-0 left-0 -ml-20 -mb-20 w-64 h-64 bg-cyan-500/10 rounded-full blur-3xl pointer-events-none" />

        <div className="inline-flex items-center space-x-2 bg-indigo-500/10 text-indigo-400 px-3 py-1 rounded-full text-sm font-medium mb-6">
          <Zap className="w-4 h-4" />
          <span>HireNexus Candidate Portal</span>
        </div>

        <h1 className="text-4xl md:text-6xl font-black text-white tracking-tight mb-6 max-w-3xl">
          Discover your next <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-cyan-400">career opportunity</span>
        </h1>

        <p className="text-slate-400 text-lg md:text-xl max-w-2xl">
          We use strictly objective, AI-driven evaluation processes to guarantee every applicant gets a fair, transparent review based on their genuine skills.
        </p>
      </div>

      {/* Open Roles Section */}
      <div>
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-2xl font-bold text-white pl-3 border-l-4 border-indigo-500">Open Roles</h2>
          <span className="text-slate-400 font-medium bg-slate-800/50 px-3 py-1 rounded-full text-sm border border-slate-700">{vacancies.length} Vacant</span>
        </div>

        {vacancies.length === 0 ? (
          <div className="bg-slate-800/40 border border-slate-700 border-dashed rounded-3xl p-12 text-center">
            <Briefcase className="w-12 h-12 text-slate-500 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-slate-300">No open roles currently</h3>
            <p className="text-slate-500 text-sm mt-1">Please check back later for new opportunities.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {vacancies.map((job, index) => (
              <motion.div
                key={job.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="group flex flex-col bg-slate-800/60 backdrop-blur-xl border border-slate-700/70 shadow-lg rounded-3xl overflow-hidden hover:border-indigo-500/50 transition-all duration-300 relative"
              >
                <div className="p-6 flex-grow border-b border-slate-700/50 flex flex-col items-start">
                  <div className="w-12 h-12 rounded-2xl bg-slate-900/50 border border-slate-700/50 flex items-center justify-center shadow-inner mb-6 group-hover:scale-110 transition-transform duration-300 shrink-0">
                    {getJobIcon(job.title)}
                  </div>

                  <h3 className="text-xl font-bold text-white mb-2 leading-snug h-14 line-clamp-2">{job.title}</h3>

                  <div className="flex flex-wrap gap-2 mb-4 w-full">
                    <span className="text-[11px] font-semibold px-2 py-1 bg-indigo-500/10 text-indigo-400 rounded-md border border-indigo-500/20">{job.experience_required}+ Yrs Exp</span>
                    <span className="text-[11px] font-semibold px-2 py-1 bg-emerald-500/10 text-emerald-400 rounded-md border border-emerald-500/20">{job.max_hires} Openings</span>
                  </div>

                  <div className="space-y-2 mt-auto w-full">
                    {job.required_skills.split(',').slice(0, 3).map((skill, i) => (
                      <div key={i} className="flex items-center text-sm text-slate-400">
                        <ShieldCheck className="w-4 h-4 text-emerald-400/70 mr-2 shrink-0" />
                        <span className="truncate">{skill.trim()}</span>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="p-4 bg-slate-900/30 flex justify-between items-center w-full">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Status</span>
                    <span className="text-sm text-emerald-400 font-medium flex items-center">
                      <span className="w-2 h-2 rounded-full bg-emerald-400 mr-2 animate-pulse"></span> Open
                    </span>
                  </div>

                  <Link
                    to={`/apply?jobId=${job.id}&jobTitle=${encodeURIComponent(job.title)}`}
                    className="bg-indigo-600 hover:bg-indigo-500 text-white font-semibold py-2 px-5 rounded-xl transition-all shadow-lg shadow-indigo-600/20 active:scale-95 flex items-center group/btn"
                  >
                    Apply <ArrowRight className="w-4 h-4 ml-2 group-hover/btn:translate-x-1 transition-transform" />
                  </Link>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

